definition.script:
pipeline {
    agent any

    parameters {
        string(name: 'COMMIT_SHA', description: 'The exact GitHub Commit SHA from UAT')
        password(name: 'AWS_ACCESS_KEY', description: 'Temporary AWS Access Key')
        password(name: 'AWS_SECRET_KEY', description: 'Temporary AWS Secret Key')
    }

    environment {
        AWS_ACCESS_KEY_ID = "${params.AWS_ACCESS_KEY}"
        AWS_SECRET_ACCESS_KEY = "${params.AWS_SECRET_KEY}"
        AWS_REGION = "ap-southeast-1"
        AWS_ACCOUNT_ID = "425629232565"
        ECR_REPO = "epiq-discovery-engine"
    }

    stages {
        stage('IM8 Gate: AWS ECR Authentication') {
            steps {
                sh '''
                echo "Authenticating Compliance Auditor with AWS Vault..."
                aws ecr get-login-password --region $AWS_REGION | docker login --username AWS --password-stdin $AWS_ACCOUNT_ID.dkr.ecr.$AWS_REGION.amazonaws.com
                '''
            }
        }

        stage('IM8 Gate: Verify Cryptographic Hash') {
            steps {
                sh '''
                echo "Pulling exact commit artifact: $COMMIT_SHA"
                docker pull $AWS_ACCOUNT_ID.dkr.ecr.$AWS_REGION.amazonaws.com/$ECR_REPO:$COMMIT_SHA
                '''
            }
        }

        stage('IM8 Gate: Trivy Vulnerability Scan') {
            steps {
                sh '''
                echo "Scanning artifact for IM8 compliance..."
                docker run --rm -v /var/run/docker.sock:/var/run/docker.sock aquasec/trivy image \
                  --severity HIGH,CRITICAL \
                  --exit-code 1 \
                  $AWS_ACCOUNT_ID.dkr.ecr.$AWS_REGION.amazonaws.com/$ECR_REPO:$COMMIT_SHA
                '''
            }
        }

        stage('IM8 Gate: Artifact Sign-Off') {
            steps {
                echo "✅ Image SHA:$COMMIT_SHA has passed all IM8 compliance checks."
                echo "✅ Cryptographic hash verified. No Critical/High vulnerabilities found."
                echo "🚀 Artifact is officially SIGNED and ready for Azure PROD deployment."
            }
        }
    }
}
